  | 'flux-kontext-pro'
  | 'flux-kontext-max'
  | 'flux-pro-1.1-ultra'
  | 'flux-pro-1.1'
  | 'flux-pro-1.0-fill'
  | (string & {});

export type BlackForestLabsAspectRatio = `${number}:${number}`;

