import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { InferSchema, Resolvable } from '@ai-sdk/provider-utils';
import {
  type FetchFunction,
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  resolve,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import type {
  PixelArtImageModelId,
  PixelArtImageSettings,
} from './pixelart-image-settings';

// ---------------------------------------------------------------------------
// Internal config passed from the provider factory to the model class
// ---------------------------------------------------------------------------

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

// ---------------------------------------------------------------------------
// Provider-specific call options schema (passed via providerOptions.pixelart)
// ---------------------------------------------------------------------------

export const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      /**
       * Output size of the generated image (e.g. "512x512", "1024x768").
       */
      size: z.string().optional(),

      /**
       * Visual style of the generated pixel-art image.
       * - "pixel"  – classic pixel-art look
       * - "retro"  – vintage CRT / console aesthetic
       * - "8bit"   – strict 8-bit colour palette
       */
      style: z.enum(['pixel', 'retro', '8bit']).optional(),

      /**
       * Pixel density (dots-per-pixel scaling factor).
       * Higher values produce larger apparent pixels.
       * Must be a positive number; typical range is 1–16.
       */
      pixelDensity: z.number().positive().optional(),
    }),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelArtImageModelOptionsSchema
>;

// ---------------------------------------------------------------------------
// Response schemas
// ---------------------------------------------------------------------------

const pixelArtImageResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      created: z.number().nullish(),
      data: z.array(
        z.object({
          b64_json: z.string(),
        }),
      ),
    }),
  ),
);

const pixelArtErrorSchema = z.object({
  error: z
    .object({
      message: z.string().optional(),
      type: z.string().optional(),
      code: z.string().optional(),
    })
    .optional(),
  message: z.string().optional(),
});

const pixelArtFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelArtErrorSchema,
  errorToMessage: error => {
    if (error?.error?.message) return error.error.message;
    if (error?.message) return error.message;
    return 'Unknown PixelArt error';
  },
});

// ---------------------------------------------------------------------------
